    {modal==="addOb"&&<ModalW title="Nueva Obra" onClose={cm}><ObraForm clientes={clis} onNewCli={nombre=>setClis(prev=>[...prev,{id:"C"+String(prev.length+1),nombre,tel:"",email:"",dir:""}])} onSave={o=>{setObras(prev=>[...prev,{...o,id:"OB"+String(prev.length+1).padStart(2,"0"),egreso:0,extras:[],pagos:[],docs:[],bitacora:[]}]);cm();show("Obra ✓");}}/></ModalW>}
    {modal==="addIng"&&<ModalW title="Ingreso + Recibo" onClose={cm}><IngForm obras={obras} onSave={m=>{const rid=genRec(m);setMovs(prev=>[...prev,{...m,id:prev.length+1,user:user.nombre}]);cm();show("Recibo "+rid);}}/></ModalW>}
    {modal==="addEgr"&&<ModalW title="Egreso" onClose={cm}><EgrForm obras={obras} provs={provs} onNewProv={nombre=>{setProvs(prev=>[...prev,{id:"P"+String(prev.length+1).padStart(2,"0"),nombre,contacto:"",tel:"",material:"",credito:0,total:0,calif:3}]);}} onSave={m=>{setMovs(prev=>[...prev,{...m,id:prev.length+1,user:user.nombre}]);cm();show("Egreso ✓");}}/></ModalW>}
    {modal==="addCj"&&<ModalW title="Gasto Caja Chica" onClose={cm}><CajaForm users={users} onSave={c=>{setCaja(prev=>[...prev,{...c,id:prev.length+1,status:user.rol==="admin"?"aprobado":"pendiente"}]);cm();show(user.rol==="admin"?"Gasto registrado":"Enviado para aprobación");}}/></ModalW>}
    {modal==="editCj"&&md&&<ModalW title="Modificar Gasto" onClose={cm}><div><Fl l="Concepto"><input style={sI} defaultValue={md.concepto} id="editCjConc"/></Fl><Fl l="Monto"><input type="number" style={sI} defaultValue={md.monto} id="editCjMonto"/></Fl><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginTop:10}}><button style={{...sB,background:"#0a2e0a",color:T.green,marginTop:0}} onClick={()=>{const nc=document.getElementById("editCjConc").value;const nm=Number(document.getElementById("editCjMonto").value);setCaja(caja.map(x=>x.id===md.id?{...x,concepto:nc||x.concepto,monto:nm||x.monto,status:"aprobado"}:x));cm();show("Aprobado con cambios ✓");}}>✓ Aprobar con cambios</button><button style={{...sB,background:"#2a0a0a",color:T.red,marginTop:0}} onClick={()=>{setCaja(caja.map(x=>x.id===md.id?{...x,status:"rechazado"}:x));cm();show("Rechazado");}}>✕ Rechazar</button></div></div></ModalW>}
    {modal==="addDoc"&&sub&&<ModalW title="Documento" onClose={cm}><DocForm onSave={d=>{const up={...sub,docs:[...(sub.docs||[]),{...d,id:(sub.docs?.length||0)+1,fecha:td(),size:"—"}]};setObras(obras.map(o=>o.id===sub.id?up:o));setSub(up);cm();show("✓");}}/></ModalW>}
    {modal==="addCli"&&<ModalW title="Cliente" onClose={cm}><ClienteForm onSave={c=>{setClis(prev=>[...prev,{...c,id:"C"+String(prev.length+1)}]);cm();show("✓");}}/></ModalW>}
    {modal==="addInv"&&<ModalW title="Material" onClose={cm}><InvForm onSave={i=>{setInv(prev=>[...prev,{...i,id:"I"+String(prev.length+1)}]);cm();show("✓");}}/></ModalW>}
    {modal==="addProv"&&<ModalW title="Proveedor" onClose={cm}><ProvForm onSave={p=>{setProvs(prev=>[...prev,{...p,id:"P"+String(prev.length+1).padStart(2,"0")}]);cm();show("✓");}}/></ModalW>}
    {modal==="addUser"&&<ModalW title="Usuario" onClose={cm}><UserForm obras={obras} onSave={u=>{setUsers(prev=>[...prev,{...u,id:Math.max(...prev.map(x=>x.id))+1}]);cm();show("Usuario ✓");}}/></ModalW>}
    {modal==="vRec"&&md&&<ModalW title={md.id} onClose={cm}><ReciboView data={md}/></ModalW>}
    {modal==="verTicket"&&md&&<ModalW title={"🧾 "+md.concepto} onClose={cm}><div style={{textAlign:"center"}}>{md.ticket&&<img src={md.ticket} style={{maxWidth:"100%",borderRadius:10,marginBottom:12}} alt="Ticket"/>}<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,textAlign:"left"}}><div><div style={{fontSize:10,color:T.muted}}>CONCEPTO</div><div style={{fontWeight:700}}>{md.concepto}</div></div><div><div style={{fontSize:10,color:T.muted}}>MONTO</div><div style={{fontWeight:800,color:T.orange,fontSize:20}}>{$(md.monto)}</div></div><div><div style={{fontSize:10,color:T.muted}}>FECHA</div><div>{fd(md.fecha)}</div></div><div><div style={{fontSize:10,color:T.muted}}>RESPONSABLE</div><div>{md.resp}</div></div></div></div></ModalW>}
